package org.example.migration;

import spoon.Launcher;
import spoon.processing.AbstractProcessor;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.code.CtExpression;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.factory.Factory;
import spoon.support.sniper.SniperJavaPrettyPrinter;

/**
 * Spoon Migration Script
 * Generated for: Generic Argument Injection Template (Missing Input Diff)
 * 
 * Strategy:
 * 1. Locate method calls matching the old signature.
 * 2. Inject the missing argument (default value).
 * 3. Use Sniper mode to preserve formatting and comments.
 */
public class RefactoringTemplate {

    public static class MethodRefactoringProcessor extends AbstractProcessor<CtInvocation<?>> {

        // TODO: Update these constants based on your actual diff
        private static final String TARGET_METHOD_NAME = "processData";
        private static final String TARGET_CLASS_NAME = "LegacyService";
        private static final int OLD_ARG_COUNT = 1;

        @Override
        public boolean isToBeProcessed(CtInvocation<?> candidate) {
            // 1. Name Check
            if (!TARGET_METHOD_NAME.equals(candidate.getExecutable().getSimpleName())) {
                return false;
            }

            // 2. Argument Count Check
            // We look for the OLD signature (missing the new argument)
            if (candidate.getArguments().size() != OLD_ARG_COUNT) {
                return false;
            }

            // 3. Type/Owner Check (Defensive for NoClasspath)
            // We use loose string matching because full type resolution fails in NoClasspath mode
            CtTypeReference<?> declaringType = candidate.getExecutable().getDeclaringType();
            if (declaringType != null) {
                String qName = declaringType.getQualifiedName();
                // Match if known class name appears, or process if type is unknown (safe fallback)
                if (!qName.contains(TARGET_CLASS_NAME) && !qName.equals("<unknown>")) {
                    return false;
                }
            }

            // 4. Advanced: Check argument types if necessary
            // Example: Skip if the first arg is not a String (defensive check)
            /*
            CtExpression<?> firstArg = candidate.getArguments().get(0);
            if (firstArg.getType() != null && !firstArg.getType().getQualifiedName().contains("String")) {
                return false;
            }
            */

            return true;
        }

        @Override
        public void process(CtInvocation<?> invocation) {
            Factory factory = getFactory();

            // TODO: Define the value to inject
            // Example: Injecting boolean 'true' as the second argument
            CtExpression<Boolean> newArg = factory.Code().createLiteral(true);

            // Alternative: Injecting a null, or a specific Enum
            // CtExpression<?> newArg = factory.Code().createCodeSnippetExpression("Context.DEFAULT");

            // Apply transformation
            invocation.addArgument(newArg);

            System.out.println("Refactored " + TARGET_METHOD_NAME + " at " + 
                (invocation.getPosition().isValidPosition() ? invocation.getPosition().toString() : "unknown line"));
        }
    }

    public static void main(String[] args) {
        // Default paths (editable by user)
        String inputPath = "./src/main/java";
        String outputPath = "./src/main/gen";

        Launcher launcher = new Launcher();
        launcher.addInputResource(inputPath);
        launcher.setSourceOutputDirectory(outputPath);

        // =======================================================================
        // CRITICAL CONFIGURATION: PRESERVE SOURCE CODE (SNIPER MODE)
        // =======================================================================

        // 1. Enable comments
        launcher.getEnvironment().setCommentEnabled(true);

        // 2. Force Sniper Printer manually to preserve formatting/indentation
        launcher.getEnvironment().setPrettyPrinterCreator(
            () -> new SniperJavaPrettyPrinter(launcher.getEnvironment())
        );

        // 3. Set NoClasspath (Allows running without building/resolving all dependencies)
        launcher.getEnvironment().setNoClasspath(true);

        // Add the processor
        launcher.addProcessor(new MethodRefactoringProcessor());

        try {
            System.out.println("Starting refactoring...");
            launcher.run();
            System.out.println("Refactoring complete. Output in: " + outputPath);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
